$("#top-slide").each(function(t, topSlide) {
	var htmlAD = "",
		pageSize1 = 3,
		pageSize2 = 2;
	$adjax({
		classifyId: "1397847673569656843",
		pageNo: 1,
		pageSize: pageSize1
	}, topSlide).done(function(res1) {
		var list1 = res1.slice(0, pageSize1);
		$.each(list1, function(i, ad) {
			htmlAD += `<div class="swiper-slide prox-row" data-title="` + ad.name + `">
							<a class="prox-col-12" target="_blank" href="` + ad.href + `">
								<img src="` + ad.image + `" height="` + ad.height + `" width="` + ad.width + `" />
							</a>
						</div>`;
		});
		$adjax({
			classifyId: "1397847673569656832",
			pageNo: 1,
			pageSize: pageSize2
		}, topSlide).done(function(res2) {
			var list2 = [];
			for (var j = 0; j < res2.length; j += pageSize2) {
				list2.push(res2.slice(j, j + pageSize2));
			}
			// var list2 = result.slice(0, pageSize1);
			$.each(list2, function(n, group) {
				htmlAD += `<div class="swiper-slide prox-row" data-title="院校传真">`;
				$.each(group, function(i, ad) {
					htmlAD += `<a class="prox-col-6" target="_blank" href="` +
						ad.href + `">
									<img src="` + ad.image + `" height="` + ad.height + `" width="` + ad.width + `" />
								</a>`;
				});
				htmlAD += `</div>`;
			});
			$("#top-slide .swiper-wrapper").append(htmlAD);
			var TopSlide = new Swiper('#top-slide', {
				autoplay: {
					delay: 3000,
					disableOnInteraction: false,
				},
				pagination: {
					el: '#top-slide .swiper-pagination',
					clickable: true,
					renderBullet: function(index, className) {
						var count = $("#top-slide .swiper-slide").length,
							width = Math.floor((1200 / count));
						return '<li class="' + className + '" style="width:' +
							width + 'px">' + $(
								"#top-slide .swiper-slide").eq(index).data(
								"title") + '</li>';
					}
				}
			});
		});
	});
});

$(".prox-row").each(function(index, item) {
	var pageNo = Number($(item).data("page"));
	var pageSize = Number($(item).data("size"));
	var params = {
		classifyId: $(item).data("classid"),
		pageNo: pageNo ? pageNo : 1,
		pageSize: pageSize ? pageSize : 20
	};
	$adjax(params, item).done(function(res) {
		var cols = 1,
			colClassName = "",
			thisHTML = '<a style="pointer-events: none; cursor: no-drop;"><em>图片加载失败</em></a>',
			data = [];
		if (res.length > 0) {
			cols = Number(res[0].educationGgClassify.cols) ? Number(res[0].educationGgClassify.cols) :
				1;
			thisHTML = "";
			data = res.slice((params.pageNo - 1) * params.pageSize, (params.pageNo - 1) * params
				.pageSize + params.pageSize);
		}
		colClassName = setColName(cols);
		$.each(data, function(i, ad) {
			thisHTML += '<div class="swiper-slide prox-item' + colClassName + '">' +
				'<a href="' + ad.href + '" target="_blank" title="' + ad.name + '">' +
				(ad.image ? '<img src="' + ad.image + '" />' : '<em>' + ad
					.educationGgClassify.treeName + '</em>') +
				'</a>' +
				'</div>';
		});
		$(this).find(".swiper-wrapper").html(thisHTML);
		var adRow = new Swiper(item, {
			speed: 0,
			autoplay: {
				delay: 3000,
				disableOnInteraction: false,
			},
			slidesPerView: cols,
			slidesPerGroup: cols,
			spaceBetween: 2
		});

	});
});

function setColName(cols) {
	var colName = "";
	switch (cols) {
		case 1:
			colName = " prox-col-12";
			break;
		case 2:
			colName = " prox-col-6";
			break;
		case 3:
			colName = " prox-col-4";
			break;
		case 4:
			colName = " prox-col-3";
			break;
		default:
			colName = " prox-col-12";
			break;
	}
	return colName;
}

$(".prox-side-group").each(function(index, item) {
	var pageNo = Number($(item).data("page"));
	var pageSize = Number($(item).data("size"));
	var params = {
		classifyId: $(item).data("classid"),
		pageNo: pageNo ? pageNo : 1,
		pageSize: pageSize ? pageSize : 20
	};
	$adjax(params, item).done(function(res) {
		var thisHTML = '<a style="pointer-events: none; cursor: no-drop;"><em>图片加载失败</em></a>',
			data = [];
		if (res.length > 0) {
			thisHTML = "";
			data = res.slice((params.pageNo - 1) * params.pageSize, (params.pageNo - 1) * params
				.pageSize + params.pageSize);
		}
		$.each(data, function(index, ad) {
			thisHTML += '<div class="swiper-slide">' +
				'<a class="prox-col-12" target="_blank" href="' + ad.href + '">' +
				(ad.image ? '<img src="' + ad.image + '" />' : '<em>' + ad
					.educationGgClassify.treeName + '</em>') +
				'</a>' +
				'</div>';
		});
		$(this).find(".swiper-wrapper").html(thisHTML);
		var adGroup = new Swiper(item, {
			autoplay: {
				delay: 3000,
				disableOnInteraction: false,
			},
			effect: 'fade',
			pagination: {
				el: '.prox-side-group .swiper-pagination',
				clickable: true
			}
		});
	});
});